// Normalize incoming lead data from website form or Meta Lead Ads
const input = $input.first().json;

// Normalize phone to E.164
let phone = (input.phone || input.phone_number || '').replace(/[^\d+]/g, '');
if (phone && !phone.startsWith('+')) {
  // Assume North American if 10 digits
  if (phone.length === 10) phone = '+1' + phone;
  else if (phone.length === 11 && phone.startsWith('1')) phone = '+' + phone;
}

const leadId = crypto.randomUUID();
const assignedAt = new Date().toISOString();

return [{
  json: {
    lead_id: leadId,
    first_name: (input.first_name || input.name || 'Unknown').trim(),
    last_name: (input.last_name || '').trim(),
    phone: phone || null,
    email: (input.email || '').trim() || null,
    source: input.source === 'meta' ? 'meta' : 'website',
    vehicle_interest: (input.vehicle_interest || input.vehicle || '').trim() || null,
    stage: 'new',
    intent_score: 'cold',
    sequence_step: 0,
    demo_mode: true,
    next_follow_up: null,
    opted_out: false,
    salesperson_alerted: false,
    sms_count: 0,
    autopilot_active: false,
    assigned_at: assignedAt,
    rep_response_at: null,
    assigned_to: null,
    _trigger_sms_immediately: false
  }
}];

const lead = $('Normalize Lead Data').first().json;
const duplicates = $input.first().json;

// If response is an array and has results, it's a duplicate
const results = Array.isArray(duplicates) ? duplicates : [duplicates];
const isDuplicate = results.length > 0 && results[0]?.id;

if (isDuplicate) {
  return [{ json: { ...lead, is_duplicate: true, existing_id: results[0].id } }];
}

return [{ json: { ...lead, is_duplicate: false } }];

// Shift-aware round-robin assignment
const baseUrl = $env.SUPABASE_URL;
const key = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = {
  'apikey': key,
  'Authorization': `Bearer ${key}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

function getMinutesInTimeZone(date, timeZone) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
    timeZone: timeZone || 'America/Toronto'
  }).formatToParts(date);

  const hours = parseInt(parts.find(part => part.type === 'hour')?.value || '0', 10);
  const minutes = parseInt(parts.find(part => part.type === 'minute')?.value || '0', 10);
  return hours * 60 + minutes;
}

function isWorking(rep, date) {
  if (!rep?.active) return false;
  const start = Number(rep.shift_start_minutes);
  const end = Number(rep.shift_end_minutes);
  if (!Number.isFinite(start) || !Number.isFinite(end) || start === end) return true;

  const nowMinutes = getMinutesInTimeZone(date, rep.shift_timezone || 'America/Toronto');
  if (start < end) {
    return nowMinutes >= start && nowMinutes < end;
  }

  return nowMinutes >= start || nowMinutes < end;
}

const repsRes = await fetch(`${baseUrl}/rest/v1/profiles?active=eq.true&select=id,name,rr_order,active,shift_start_minutes,shift_end_minutes,shift_timezone`, { headers });
const repsRaw = await repsRes.json();
const now = new Date();
const reps = (Array.isArray(repsRaw) ? repsRaw : [])
  .filter(rep => isWorking(rep, now))
  .sort((a, b) => {
    const orderDiff = (a.rr_order ?? 0) - (b.rr_order ?? 0);
    if (orderDiff !== 0) return orderDiff;
    return (a.name || '').localeCompare(b.name || '');
  });

if (reps.length === 0) {
  return [{ json: { ...$input.first().json, assigned_to: null, autopilot_active: true, _trigger_sms_immediately: true } }];
}

const settingsRes = await fetch(`${baseUrl}/rest/v1/settings?key=eq.rr_index&select=value`, { headers });
const settings = await settingsRes.json();
const rawIndex = settings[0]?.value ?? 0;
const currentIndex = typeof rawIndex === 'number' ? rawIndex : parseInt(String(rawIndex).replace(/[^\d-]/g, ''), 10) || 0;
const idx = ((currentIndex % reps.length) + reps.length) % reps.length;
const assignedRep = reps[idx];
const nextIndex = (idx + 1) % reps.length;

await fetch(`${baseUrl}/rest/v1/settings?key=eq.rr_index`, {
  method: 'PATCH',
  headers: { ...headers, 'Prefer': 'return=minimal' },
  body: JSON.stringify({ value: nextIndex })
});

return [{ json: { ...$input.first().json, assigned_to: assignedRep.id, autopilot_active: false, _trigger_sms_immediately: false } }];

const insertedLead = $input.first().json;
const leadId = Array.isArray(insertedLead) ? insertedLead[0]?.id : insertedLead?.id;
const assignedLead = $('Round Robin Assign').first().json;

if (!leadId || !assignedLead?._trigger_sms_immediately) {
  return [{ json: insertedLead }];
}

await fetch($env.N8N_WEBHOOK_SMS_ENGINE, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ lead_id: leadId, trigger_type: 'first_contact' })
});

return [{ json: insertedLead }];
